from typing import List, Dict, Any, Optional, Callable
from leann.api import SearchResult
from leann.metadata_filter import MetadataFilterEngine
from collections import defaultdict

def aggregate_search_results(
    search_results: List[SearchResult],
    group_by_field: str,
    aggregation_funcs: Optional[Dict[str, Callable]] = None
) -> Dict[str, Dict[str, Any]]:
    """Aggregate search results by a metadata field with optional statistics.

    Args:
        search_results: List of SearchResult objects to aggregate
        group_by_field: Metadata field name to group by
        aggregation_funcs: Optional dictionary mapping field_name to aggregation function.
            Example: {"score": max, "count": len}
            If None, defaults to count and average score per group

    Returns:
        Dictionary mapping group_value to aggregated statistics
        Example: {"tech": {"count": 5, "avg_score": 0.85, "max_score": 0.95}}
    """
    # Initialize aggregation dictionary
    aggregated_data = defaultdict(lambda: {
        'count': 0,
        'sum_score': 0.0,
        'max_score': float('-inf'),
        'min_score': float('inf'),
        'custom_aggregations': {}
    })

    # Process each search result
    for result in search_results:
        # Extract group value from metadata
        group_value = result.metadata.get(group_by_field)

        # Handle missing group values
        if group_value is None or group_value == "":
            group_value = 'unknown'

        # Update default statistics
        group_data = aggregated_data[group_value]
        group_data['count'] += 1
        group_data['sum_score'] += result.score

        if result.score > group_data['max_score']:
            group_data['max_score'] = result.score

        if result.score < group_data['min_score']:
            group_data['min_score'] = result.score

    # Calculate average scores
    for group_value, group_data in aggregated_data.items():
        if group_data['count'] > 0:
            group_data['avg_score'] = group_data['sum_score'] / group_data['count']
        else:
            group_data['avg_score'] = 0.0

    # Apply custom aggregation functions if provided
    if aggregation_funcs:
        for group_value, group_data in aggregated_data.items():
            for field_name, func in aggregation_funcs.items():
                # Extract values for the specified field
                field_values = []
                for result in search_results:
                    group_val = result.metadata.get(group_by_field)
                    if group_val is None or group_val == "":
                        group_val = 'unknown'

                    if group_val == group_value:
                        # Get field value (check both top-level and metadata)
                        field_value = getattr(result, field_name, None)
                        if field_value is None:
                            field_value = result.metadata.get(field_name)
                        field_values.append(field_value)

                try:
                    aggregated_value = func(field_values)
                    group_data['custom_aggregations'][field_name] = aggregated_value
                except Exception as e:
                    # Handle cases where aggregation might fail
                    group_data['custom_aggregations'][field_name] = None

    # Convert to final dictionary format
    final_result = {}
    for group_value, group_data in aggregated_data.items():
        # Combine default stats with custom aggregations
        stats = {
            'count': group_data['count'],
            'avg_score': group_data['avg_score'],
            'max_score': group_data['max_score'],
            'min_score': group_data['min_score']
        }

        # Add custom aggregations if they exist
        if group_data['custom_aggregations']:
            stats.update(group_data['custom_aggregations'])

        final_result[group_value] = stats

    return final_result

